import moment from "moment"
import dayjs from "dayjs"
import customParseFormat from "dayjs/plugin/customParseFormat"

// Enable custom parse format plugin
dayjs.extend(customParseFormat)

// Hàm chuyển đổi từ yyyy-mm-dd sang dd-mm-yyyy
const convertDateFormat = (
  dateString,
  fromFormat = "YYYY-MM-DD",
  toFormat = "DD-MM-YYYY",
) => {
  if (!dateString) return null

  // Parse date với format đầu vào
  const parsedDate = dayjs(dateString, fromFormat, true)

  if (!parsedDate.isValid()) {
    console.warn(`Không thể parse date: ${dateString} với format ${fromFormat}`)
    return null
  }

  // Format lại theo format đầu ra
  return parsedDate.format(toFormat)
}

// Hàm chuyển đổi ngược từ dd-mm-yyyy sang yyyy-mm-dd
const convertDateFormatReverse = (
  dateString,
  fromFormat = "DD-MM-YYYY",
  toFormat = "YYYY-MM-DD",
) => {
  if (!dateString) return null

  const parsedDate = dayjs(dateString, fromFormat, true)

  if (!parsedDate.isValid()) {
    console.warn(`Không thể parse date: ${dateString} với format ${fromFormat}`)
    return null
  }

  return parsedDate.format(toFormat)
}

// Helper function để parse date từ CCCD với nhiều format khác nhau (đã cải tiến)
const parseDate = dateString => {
  if (!dateString) return null

  // Loại bỏ spaces và normalize string
  const cleanDateString = dateString.toString().trim()

  if (!cleanDateString) return null

  // Các format date thường gặp trong CCCD và hệ thống
  const dateFormats = [
    "YYYY-MM-DD", // ISO format (từ server)
    "DD/MM/YYYY", // Vietnamese format
    "DD-MM-YYYY", // Vietnamese format with dash
    "MM/DD/YYYY", // US format
    "YYYY/MM/DD", // Alternative ISO format
  ]

  // Thử parse với từng format
  for (const format of dateFormats) {
    const parsed = dayjs(cleanDateString, format, true) // strict parsing
    if (parsed.isValid()) {
      return parsed
    }
  }

  // Thử parse tự động với dayjs
  const autoParsed = dayjs(cleanDateString)
  if (autoParsed.isValid()) {
    return autoParsed
  }

  // Nếu là dạng DDMMYYYY (8 chữ số liền nhau)
  if (/^\d{8}$/.test(cleanDateString)) {
    const day = cleanDateString.substring(0, 2)
    const month = cleanDateString.substring(2, 4)
    const year = cleanDateString.substring(4, 8)
    const formatted = `${day}/${month}/${year}`
    const parsed = dayjs(formatted, "DD/MM/YYYY")
    if (parsed.isValid()) {
      return parsed
    }
  }

  // Nếu là dạng YYYYMMDD (8 chữ số liền nhau, năm ở đầu)
  if (/^\d{8}$/.test(cleanDateString)) {
    const year = cleanDateString.substring(0, 4)
    const month = cleanDateString.substring(4, 6)
    const day = cleanDateString.substring(6, 8)
    const formatted = `${year}-${month}-${day}`
    const parsed = dayjs(formatted, "YYYY-MM-DD")
    if (parsed.isValid()) {
      return parsed
    }
  }

  console.warn(`Không thể parse date: ${dateString}`)
  return null
}

// Hàm format date để hiển thị theo định dạng Việt Nam
const formatDateVN = (date, format = "DD/MM/YYYY") => {
  if (!date) return ""

  if (dayjs.isDayjs(date)) {
    return date.format(format)
  }

  const parsedDate = dayjs(date)
  if (parsedDate.isValid()) {
    return parsedDate.format(format)
  }

  return ""
}

// Hàm format date để gửi lên server (ISO format)
const formatDateForServer = (date, format = "YYYY-MM-DD") => {
  if (!date) return ""

  if (dayjs.isDayjs(date)) {
    return date.format(format)
  }

  const parsedDate = dayjs(date)
  if (parsedDate.isValid()) {
    return parsedDate.format(format)
  }

  return ""
}

// Validation cho date fields
const validateDate = (_, value) => {
  if (!value) {
    return Promise.reject("Vui lòng chọn ngày")
  }

  if (!dayjs.isDayjs(value) || !value.isValid()) {
    return Promise.reject("Ngày không hợp lệ")
  }

  // Kiểm tra không được chọn ngày tương lai
  const today = dayjs().endOf("day") // Lấy cuối ngày hôm nay
  if (value.isAfter(today)) {
    return Promise.reject("Ngày cấp CCCD không được là ngày tương lai")
  }

  return Promise.resolve()
}

const validateBirthDate = (_, value) => {
  if (!value) {
    return Promise.reject("Vui lòng chọn ngày sinh")
  }

  if (!dayjs.isDayjs(value) || !value.isValid()) {
    return Promise.reject("Ngày sinh không hợp lệ")
  }

  const today = dayjs().endOf("day")
  if (value.isAfter(today)) {
    return Promise.reject("Ngày sinh không được là ngày tương lai")
  }

  const minDate = dayjs().subtract(150, "year") // Giới hạn 150 tuổi
  if (value.isBefore(minDate)) {
    return Promise.reject("Ngày sinh không hợp lệ")
  }

  return Promise.resolve()
}

/**
 * Validate date format for business registration
 */
const validateBusinessDate = date => {
  if (!date) return false
  const parsedDate = dayjs(date)
  return parsedDate.isValid()
}

/**
 * Validate date range for business registration
 */
const validateBusinessDateRange = date => {
  if (!date) return false
  const parsedDate = dayjs(date)
  const today = dayjs()
  return parsedDate.isValid() && parsedDate.isBefore(today)
}

/**
 * Format business date for display
 */
const formatBusinessDate = date => {
  if (!date) return ""
  const parsedDate = dayjs(date)
  if (parsedDate.isValid()) {
    return parsedDate.format("DD/MM/YYYY")
  }
  return ""
}

/**
 * Parse CCCD QR data
 */
export const parseIDCardData = qrData => {
  try {
    const parts = qrData.split("|")
    if (parts.length >= 6) {
      return {
        id: parts[0] || "",
        name: parts[2] || "",
        birthDate: parts[3] ? formatDDMMYYYY(parts[3]) : "",
        gender: parts[4] || "",
        address: parts[5] || "",
        issueDate: parts[6] ? formatDDMMYYYY(parts[6]) : "",
        raw: qrData,
      }
    }
  } catch (err) {
    console.error("Lỗi phân tích dữ liệu:", err)
  }
  return { raw: qrData }
}

/**
 * Format date from DDMMYYYY to DD/MM/YYYY
 */
export const formatDDMMYYYY = input => {
  const d = input.slice(0, 2)
  const m = input.slice(2, 4)
  const y = input.slice(4, 8)
  return `${d}/${m}/${y}`
}

/**
 * Format date for API submission
 */
export const formatDate = date => {
  if (!date) return null
  if (moment.isMoment(date)) {
    return date.toISOString()
  }
  if (typeof date === "string") {
    return moment(date, "DD/MM/YYYY").toISOString()
  }
  return null
}

/**
 * Validate required CCCD fields
 */
export const validateCCCDData = cccdData => {
  const requiredFields = {
    FullName: cccdData?.name,
    DateOfBirth: cccdData?.birthDate,
    Identification: cccdData?.id,
  }

  const missingFields = Object.entries(requiredFields)
    .filter(([_, value]) => !value)
    .map(([key]) => key)

  return {
    isValid: missingFields.length === 0,
    missingFields,
  }
}

/**
 * Build full address string
 */
export const buildFullAddress = (
  streetAddress,
  wardName,
  districtName,
  provinceName,
) => {
  return [streetAddress, wardName, districtName, provinceName]
    .filter(Boolean)
    .join(", ")
}

export {
  convertDateFormat,
  convertDateFormatReverse,
  parseDate,
  formatDateVN,
  formatDateForServer,
  validateDate,
  validateBirthDate,
  validateBusinessDate,
  validateBusinessDateRange,
  formatBusinessDate,
}
